INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (3, 1, "travel_topdrama_r_2000_talk_anger_shy", 20012, 0.2, 1, "", 1200120008, "", "", 106011);
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (21, 0, "vo_travel_talk_20001_01", 20012, "", "", "", 1200120009, "", 0, "vo_travel_talk");
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (11, 10, "あんたね、なにもかも間違ってるわよ！\n探すのはお宝だし、魔物は食材じゃ\nないんだってば！", 20012, 0, 1, 0, 1200120010, 0, 1, 106011);
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (91, "", "", 20012, "", "", "", 1200120011, "", "", 0);
