INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (3, 0, "travel_topdrama_r_2000_talk_smile_in", 20012, 0.2, 1, "", 1200120013, "", "travel_topdrama_r_2000_talk_smile_loop", 105811);
