INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (11, 10, "どういたしまして♪\nケガはないのが一番だけど、\n困ったときは遠慮なく相談してね？", 20022, 0, 1, 0, 1200220013, 0, 1, 100211);
