INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (11, 10, "冒険はね、準備が大事なんだよ！\nだから迷わないようにコンパスを\n持ってきたんだ～♪", 20032, 0, 1, 0, 1200320005, 0, 1, 100411);
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (91, "", "", 20032, "", "", "", 1200320006, "", "", 0);
