INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (11, 10, "そうかい。\nじゃあまずは、焚火の枝を集める運命を\n受け入れてもらえるかい？", 20052, 0, 1, 0, 1200520010, 0, 1, 105611);
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (91, "", "", 20052, "", "", "", 1200520011, "", "", 0);
