INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (11, 10, "えっと、こんな感じですか？\n……わわっ、バランスが！？\nなかなか難しいですね……", 20072, 0, 1, 0, 1200720010, 0, 1, 105411);
