INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (11, 10, "なに言ってるべさ～！\nリンリンこそしっかり歩いて、\n体を鍛え直さねぇと！", 20102, 0, 1, 0, 1201020010, 0, 1, 103311);
