INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (3, 0, "travel_topdrama_r_2000_talk_surprise2_in", 20142, 0.2, 1, "", 1201420008, "", "travel_topdrama_r_2000_talk_surprise2_loop", 102811);
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (21, 0, "vo_travel_talk_20014_01", 20142, "", "", "", 1201420009, "", 0, "vo_travel_talk");
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (11, 10, "危ないっ！　……石につまづいたの？\nもう、しっかりしなさいよね？\nあなたのこと、頼りにしてるんだから。", 20142, 0, 1, 0, 1201420010, 0, 1, 102811);
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (91, "", "", 20142, "", "", "", 1201420011, "", "", 0);
