INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (11, 10, "ねねね！\nみんなで記念撮影しよ？\nあとで見返したら絶対エモいっしょ！", 20162, 0, 1, 0, 1201620005, 0, 1, 101611);
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (91, "", "", 20162, "", "", "", 1201620006, "", "", 0);
