INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (3, 0, "travel_topdrama_r_2000_talk_arm_crossed_in_sad", 20172, 0.2, 1, "", 1201720008, "", "travel_topdrama_r_2000_talk_arm_crossed_loop_sad", 106611);
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (21, 0, "vo_travel_talk_20017_01", 20172, "", "", "", 1201720009, "", 0, "vo_travel_talk");
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (11, 10, "あ、相変わらずのケンカバカですね……\nあたしはこんな面倒な仕事放り出して、\nさっさとランドソルに帰りてーですよ。", 20172, 0, 1, 0, 1201720010, 0, 1, 106611);
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (91, "", "", 20172, "", "", "", 1201720011, "", "", 0);
