INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (21, 0, "vo_travel_talk_20018_00", 20182, "", "", "", 1201820003, "", 0, "vo_travel_talk");
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (11, 10, "ぜぇ……ぜぇ……！\n本来、このような探索などは文官である\nわたくしの管轄外なのですけれど……！", 20182, 0, 1, 0, 1201820004, 0, 1, 118011);
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (91, "", "", 20182, "", "", "", 1201820005, "", "", 0);
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (3, 0, "travel_topdrama_r_2000_talk_doya_in", 20182, 0.2, 1, "", 1201820006, "", "travel_topdrama_r_2000_talk_doya_loop", 118011);
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (21, 0, "vo_travel_talk_20018_01", 20182, "", "", "", 1201820007, "", 0, "vo_travel_talk");
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (11, 10, "陛下直々のご命令とあれば、\nこのクレジッタ・キャッシュ！\nご満足いただける大秘宝を、\nなんとしても手に入れてみせますわ！", 20182, 0, 1, 0, 1201820008, 0, 1, 118011);
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (91, "", "", 20182, "", "", "", 1201820009, "", "", 0);
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (3, 1, "travel_topdrama_r_2000_talk_thinking", 20182, 0.2, "", "", 1201820010, "", "", 118011);
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (21, 0, "vo_travel_talk_20018_02", 20182, "", "", "", 1201820011, "", 0, "vo_travel_talk");
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (11, 10, "……それに、手ぶらで帰ったとなると\n秘書にまた小言を言われそうですし。\nあの子がグゥの音も出なくなるくらい\n稼いで稼いで稼ぎますわよ～っ！", 20182, 0, 1, 0, 1201820012, 0, 1, 118011);
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (91, "", "", 20182, "", "", "", 1201820013, "", "", 0);
