INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (11, 10, "オマエが言うと説得力あるな……\nけど、大悪党はこっそりなんてしない！\nド派手に、バーっと暴れまわるんだ！", 20192, 0, 1, 0, 1201920015, 0, 1, 106111);
