INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (11, 10, "多くの方々に依頼をかけましたが、\nギルドの垣根を越えて協力し合い、\n調査が進んでいるようですね。", 20202, 0, 1, 0, 1202020004, 0, 1, 118511);
