INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (11, 10, "うわあー！　すごいッス！　絶景ッス！\nかっこいいッスー！　トラタイガーが\n修行してる場所みたいッスー！", 20252, 0, 1, 0, 1202520005, 0, 1, 100511);
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (91, "", "", 20252, "", "", "", 1202520006, "", "", 0);
