INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (11, 10, "アハハ、不機嫌顔だね。ま、いきなり\n引っ張り出されたらそりゃ不満か。\nほらほら、冒険だよ、楽しまなくちゃ！", 20282, 0, 1, 0, 1202820005, 0, 1, 106811);
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (91, "", "", 20282, "", "", "", 1202820006, "", "", 0);
